const path=require("path");const{execSync}=require("child_process");const fs=require("fs");const hooksDir=__dirname;const autoFormatter=require(path.join(hooksDir,"autoFormatter.js"));const buildChecker=require(path.join(hooksDir,"buildChecker.js"));const observe=require(path.join(hooksDir,"observe.js"));let outputSecretFilter;try{outputSecretFilter=require(path.join(hooksDir,"outputSecretFilter.js"))}catch(e){}function runShellHook(scriptName,stdinData,timeoutMs=5e3){const scriptPath=path.join(hooksDir,scriptName);if(!fs.existsSync(scriptPath))return;try{const result=execSync(`bash "${scriptPath}"`,{input:JSON.stringify(stdinData),timeout:timeoutMs,encoding:"utf8",stdio:["pipe","pipe","pipe"]});if(result&&result.trim()){process.stdout.write(result)}}catch(e){process.stderr.write(`[Orchestrator] ${scriptName} error: ${e.message}\n`)}}async function orchestrate(event){const toolName=event.tool_name||event.tool||"";const toolInput=event.tool_input||{};const filePath=toolInput.file_path||"";const isEditWrite=["Edit","Write"].includes(toolName);const isBash=toolName==="Bash";const isScss=filePath.endsWith(".scss");if(isEditWrite){try{const hookEvent={tool:toolName,parameters:toolInput};await autoFormatter.onPostToolUse(hookEvent)}catch(e){process.stderr.write(`[Orchestrator] autoFormatter: ${e.message}\n`)}}if(isEditWrite){try{const context={editedFiles:filePath?[filePath]:[]};await buildChecker.onPostToolUse(context)}catch(e){process.stderr.write(`[Orchestrator] buildChecker: ${e.message}\n`)}}if(isEditWrite&&isScss){runShellHook("scssValidator.sh",event)}if(isEditWrite){runShellHook("gemini-collector.sh",event)}if(isBash&&outputSecretFilter&&outputSecretFilter.filterSecrets){try{outputSecretFilter.filterSecrets(event)}catch(e){process.stderr.write(`[Orchestrator] outputSecretFilter: ${e.message}\n`)}}try{observe.processEvent(event)}catch(e){process.stderr.write(`[Orchestrator] observe: ${e.message}\n`)}}if(require.main===module){let input="";process.stdin.setEncoding("utf8");process.stdin.on("data",chunk=>{input+=chunk});process.stdin.on("end",async()=>{try{const event=JSON.parse(input);await orchestrate(event);process.exit(0)}catch(e){process.stderr.write(`[Orchestrator] Parse error: ${e.message}\n`);process.exit(0)}});setTimeout(()=>{process.exit(0)},18e4)}module.exports={orchestrate:orchestrate};